168	const maxBufferSize = 8 * format.MegaByte
169	
170	func (c *Client) stream(ctx context.Context, method, path string, data any, fn func([]byte) error) error {
171		var buf io.Reader
172		if data != nil {
173			bts, err := json.Marshal(data)
174			if err != nil {
175				return err
176			}
177	
178			buf = bytes.NewBuffer(bts)
179		}
180	
181		requestURL := c.base.JoinPath(path)
182	
183		var token string
184		if envconfig.UseAuth() || c.base.Hostname() == "ollama.com" {
185			var err error
186			now := strconv.FormatInt(time.Now().Unix(), 10)
187			chal := fmt.Sprintf("%s,%s?ts=%s", method, path, now)
188			token, err = getAuthorizationToken(ctx, chal)
189			if err != nil {
190				return err
191			}
192	
193			q := requestURL.Query()
194			q.Set("ts", now)
195			requestURL.RawQuery = q.Encode()
196		}
197	
198		request, err := http.NewRequestWithContext(ctx, method, requestURL.String(), buf)
199		if err != nil {
200			return err
201		}
202	
203		request.Header.Set("Content-Type", "application/json")
204		request.Header.Set("Accept", "application/x-ndjson")
205		request.Header.Set("User-Agent", fmt.Sprintf("ollama/%s (%s %s) Go/%s", version.Version, runtime.GOARCH, runtime.GOOS, runtime.Version()))
206	
207		if token != "" {
208			request.Header.Set("Authorization", token)
209		}
210	
211		response, err := c.http.Do(request)
212		if err != nil {
213			return err
214		}
215		defer response.Body.Close()
216	
217		scanner := bufio.NewScanner(response.Body)
218		// increase the buffer size to avoid running out of space
219		scanBuf := make([]byte, 0, maxBufferSize)
220		scanner.Buffer(scanBuf, maxBufferSize)
221		for scanner.Scan() {
222			var errorResponse struct {
223				Error     string `json:"error,omitempty"`
224				SigninURL string `json:"signin_url,omitempty"`
225			}
226	
227			bts := scanner.Bytes()
228			if err := json.Unmarshal(bts, &errorResponse); err != nil {
229				if response.StatusCode >= http.StatusBadRequest {
230					return StatusError{
231						StatusCode:   response.StatusCode,
232						Status:       response.Status,
233						ErrorMessage: string(bts),
234					}
235				}
236				return errors.New(string(bts))
237			}
238	
239			if response.StatusCode == http.StatusUnauthorized {
240				return AuthorizationError{
241					StatusCode: response.StatusCode,
242					Status:     response.Status,
243					SigninURL:  errorResponse.SigninURL,
244				}
245			} else if response.StatusCode >= http.StatusBadRequest {
246				return StatusError{
247					StatusCode:   response.StatusCode,
248					Status:       response.Status,
249					ErrorMessage: errorResponse.Error,
250				}
251			}
252	
253			if errorResponse.Error != "" {
254				return errors.New(errorResponse.Error)
255			}
256	
257			if err := fn(bts); err != nil {
258				return err
259			}
260		}
261	
262		return nil
263	}
