434				remoteModel := info.RemoteModel
435				if remoteModel == "" {
436					remoteModel = opts.Model
437				}
438				if isCloud {
439					fmt.Fprintf(os.Stderr, "Connecting to '%s' on 'ollama.com' ⚡\n", remoteModel)
